function getFraction(o,t){let r=0,n=0;return o>4999?o%25==0?o:"up"==t?(r=o%25,o+(25-(n=Math.floor(r)))):(r=o%25,o-(n=Math.floor(r))):o>1999?o%10==0?o:"up"==t?(r=o%10,o+(10-(n=Math.floor(r)))):(r=o%10,o-(n=Math.floor(r))):o>499?o%5==0?o:"up"==t?(r=o%5,o+(5-(n=Math.floor(r)))):(r=o%5,o-(n=Math.floor(r))):o>199?o%2==0?o:"up"==t?(r=o%2,o+(2-(n=Math.floor(r)))):(r=o%2,o-(n=Math.floor(r))):o}function incrementPriceStock(o,t){let r=0;for(r=o>4999?25:o>1999?10:o>499?5:o>199?2:1,i=0;i<t;i++)o+=r;return o}function getLowBodyPrice(o,t){return t<o?t:o}function getHighBodyPrice(o,t){return t<o?o:t}